import { getCartDeviceId } from "../cart/cart";
import { getLoggedInCid } from "../auth/session";
import {
  createWishlistItem,
  deleteWishlistItem,
  getWishlistByCustomer,
  getWishlistByDevice,
} from "./wishlist";

export function getWishlistProductId(item) {
  if (item?.pid && typeof item.pid === "object") return item.pid._id || item.pid.id;
  return item?.pid || item?.productId || item?.id || null;
}

export async function loadWishlistItems() {
  const cid = getLoggedInCid();
  const deviceId = getCartDeviceId();
  if (!cid && !deviceId) return [];

  const res = cid
    ? await getWishlistByCustomer(cid)
    : await getWishlistByDevice(deviceId);

  return Array.isArray(res?.data?.data)
    ? res.data.data
    : Array.isArray(res?.data)
      ? res.data
      : [];
}

export async function toggleWishlistProduct(product, wishlistItems) {
  const productId = product?._id || product?.id || product?.productId;
  if (!productId) return { items: wishlistItems, changed: false };

  const existingItem = wishlistItems.find(
    (item) => getWishlistProductId(item) === productId
  );

  if (existingItem?._id) {
    await deleteWishlistItem(existingItem._id);
    return {
      items: wishlistItems.filter((item) => item._id !== existingItem._id),
      changed: true,
    };
  }

  const cid = getLoggedInCid();
  const deviceId = getCartDeviceId();
  const res = await createWishlistItem({
    cid: cid || null,
    pid: productId,
    divid: deviceId,
    qty: 1,
    variantId: product.defaultVariant?._id || product.variantId || null,
    venderid: product.vendorId || product.venderid || null,
    offerDiscount: product.discount || 0,
  });

  const created = res?.data?.data;
  return {
    items: created ? [...wishlistItems, created] : wishlistItems,
    changed: Boolean(created),
  };
}
